### 7. Gerador de plano

```js
// src/plan.js
export function generatePlan({ columns, tables, where }) {
  const steps = [];
  const conds = where ? where.split(/\band\b/).map(c => c.trim()) : [];

  tables.forEach(t => {
    steps.push(`Scan ${t}`);
    const cond = conds.find(c => c.includes(t));
    if (cond) steps.push(`σ filtrar: ${cond}`);
  });

  if (tables.length > 1) steps.push(`⨝ ${tables.join(' ⨝ ')}`);
  steps.push(`π projetar colunas: ${columns.join(', ')}`);
  return steps;
}
```

